import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { FormGroup, FormHelperText, FormLabel, TextField } from '@material-ui/core';
import { HIRButton } from '../../Includes';
import { Cancel, Done } from '@material-ui/icons';
import { errorNotice, hirUtil } from '../../utils';


const style = theme => ({
    root: {
    }, 
    btn : {
        marginRight : 20
    }
})
class _HIRNewDeposit extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data : {
                amount : 0,
                description : '',
                actionDate : new Date(),
            },
            loading : false,
        }
        const {dispatch, onEdit, data} = this.props;
        if(onEdit && data){
            this.state.data = {
                ...this.state.data, 
                amount : data.amount,
                description : data.description,
                actionDate : new Date(data.actionDate).toLocaleDateString()
            }
        }
        this.formConfig = [
            {name : 'amount', label : 'Amount', type : "number"},
            {name : "description", label : "Description"}
        ];
        if(hirUtil.isAdmin())
            this.formConfig.push({name : "actionDate", label : "Deposit Date", type: "date", description : "Leave deposit date empty to use today's date!"});
    }
    onChange = name => e => {
        const value = e.target.value;
        const {data} = this.state;
        this.setState({data : {...data, [name] : value}});
    }
    createDeposit(){
        const {data} = this.state,
        {amount} = data,
        {dispatch, onCreateDeposit, onUpdateDeposit, onEdit} = this.props;
        if(!amount) return errorNotice("Amount not set!", dispatch);
        const callback = () => this.setState({loading : false});
        data.amount = parseInt(amount);
        if(onEdit && onUpdateDeposit){
            this.setState({loading : true});
            onUpdateDeposit(data, callback)
        }else if(onCreateDeposit){
            this.setState({loading : true});
            onCreateDeposit(data, callback);
        }
    }
    render() {
        const {classes, title, onEdit, onCancel} = this.props,
        {data, loading} = this.state;

        return (
            <div className={classes.root}>
                <FormGroup>
                    <FormLabel>{title || "New Deposit"}</FormLabel>
                    <div style={{marginTop : 40}}/>
                    {this.formConfig.map((field, index)=>{
                        const {name, label, description, ...others} = field;
                        return <Fragment key={index}>
                            {name === "amount" && <FormHelperText>{Number(data[name]).toLocaleString()}</FormHelperText>}
                            <TextField
                                style={{marginBottom : 20}}
                                label={label}
                                variant="outlined"
                                placeholder={label}
                                onChange={this.onChange(name)}
                                value={data[name]}
                                {...others}
                            />    
                            {description && <FormHelperText>{description}</FormHelperText>}
                        </Fragment>
                    })} 
                    <div style={{marginTop : 20}}>
                        <HIRButton
                            classes={{btn : classes.btn}}
                            type="secondary"
                            onClick={onCancel}
                        >
                            <Cancel fontSize="small"/>
                            Cancel
                        </HIRButton>
                        <HIRButton
                            onClick={this.createDeposit.bind(this)}
                            loading={loading}
                        >
                            <Done fontSize="small"/>
                            {onEdit ? "Update " : "Create "} Deposit
                        </HIRButton>
                    </div>
                    </FormGroup>
            </div>
        );
    }
}


_HIRNewDeposit.propTypes = {
    classes : PropTypes.object.isRequired,
    onCancel : PropTypes.func,
    onCreateDeposit : PropTypes.func,
    onUpdateDeposit : PropTypes.func,
    onEdit : PropTypes.bool,
    data : PropTypes.object,
};

export const HIRNewDeposit = connect()(withStyles(style)(_HIRNewDeposit));
export {HIRNewDeposit as default}