import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { hirUtil, hirUtilStrings } from '../../../utils';
import { Fab, TableCell, Button, MenuItem, Menu } from '@material-ui/core';
import { Add, Edit, Delete } from '@material-ui/icons';
import { MyDialog, MyTable } from '../../../utils';
import { HIRNewPayment } from "../../../HIRAccounts";
import { hirPatientActions } from '../../actions';
import { hirPatientStrings } from '../../config';
import { hirSettingStrings, hirSettingActions } from '../../../HIRSettings';
import { HIRReceipt } from '../../../HIRAccounts/HIRReceipt/HIRReceipt';
import { appActions } from '../../../../../actions';
import { HIRMultiplePayment } from '../../../HIRAccounts/HIRNewPayment/HIRMultiplePayment';
import { HIRReceiptMultiple } from '../../../HIRAccounts/HIRReceipt/HIRReceiptMultiple';

const style = theme => ({
    root: {
        paddingBottom : 50
    },
    fab : {},
    icon :{},
    table : {
        backgroundColor : "transparent",
    },
    cell : {
        padding : 5,
        fontSize : 11,
    },
    dialogPaper : {
        display : 'flex',
        justifyContent : "center",
        alignItems : "center",
    },
    group : {
        "&:hover" : {
            textDecoration : "underline",
        }
    },
    tableWrapper : {
        maxHeight : "10cm"
    }
})
class _HIRPayments extends Component {    
    state = {
        newPayDialog : false,
        printDialog : false,
        editMode : false,
        payment : null,
        anchorEl : null
    }
    componentDidMount() {
        const {
            dispatch, patientId,
            [hirSettingStrings.settings] : settings
        } = this.props;
        if(!settings) hirSettingActions.getSettings()(dispatch);
        hirPatientActions.getPatientPayments(patientId)(dispatch);
    }
    
    postPayment(data, context) {
        const {dispatch, patientId, patient, updateUser} = this.props;
        data.amount = parseInt(data.amount);
        hirPatientActions.postPayment(patientId, data, (done, result) => {
            context.setState({loading : false});
            if(done) {
                updateUser && updateUser({updateHeader : false})
                let lastName, firstName;
                if(patient && patient.myProfile){
                    const {myProfile} = patient;
                    lastName = myProfile.lastName;
                    firstName = myProfile.firstName;
                }
                this.setState({
                    newPayDialog : false, 
                    payment : { ...result, name : lastName && lastName + ", "+firstName}, 
                    printDialog : true
                });                
            }
        })(dispatch);
    }
    deletePayment = (paymentId, groupId) => () => {
        const {dispatch, patientId, updateUser} = this.props;
        appActions.closeSnackDialog()(dispatch);
        hirPatientActions.deletePayment(patientId, paymentId, groupId, done => {
            done && updateUser && updateUser({updateHeader : false})
        })(dispatch);
    }
    deletePaymentWarning = payment => e => {
        e.preventDefault();
        e.stopPropagation();
        const {dispatch} = this.props;
        appActions.showSnackDialog(
            "Are you sure you want to delete payment?",
            [<Button 
                key={"deletePatientPayment"+payment._id}
                onClick={this.deletePayment(payment._id,payment.groupId)}>Delete</Button>]
        )(dispatch);
    }
    openMultipleReceipt = payment => e => {
        e.stopPropagation();
        this.setState({payment, printDialog : true, multiple : true});
    }
    cellMapFormat = ({row, cellMap}) => {
        const {classes, 
            [hirSettingStrings.settings] : settings,
            [hirUtilStrings.myProfile] : profile
        } =this.props;
        switch(cellMap){
            case "accountAction" : return <TableCell className={classes.cell}>
                {row[cellMap] ? (row[cellMap] === "useCredit" ? "Deposit" : "Debt") : "Cash"}
            </TableCell>
            case "groupId" : return <TableCell className={classes.cell}>
                {row[cellMap] && <strong onClick={this.openMultipleReceipt(row)} className={classes.group}>
                    {String(row[cellMap]).substr(0, 3)}
                    ...
                    {String(row[cellMap]).substr(row[cellMap].length - 4, 4)}
                </strong>}
            </TableCell>
            case "action" : return <TableCell className={classes.cell}>
                {profile && [0,11].indexOf(profile.privilege) !== -1 && <div>
                    <Edit 
                        onClick={this.editPaymentDialog(row)}
                        fontSize="small" 
                        style={{color : "gray"}}/>
                    <Delete onClick={this.deletePaymentWarning(row)} fontSize="small" color="secondary"/>
                </div>}
            </TableCell>
            case "amount" : return <TableCell className={classes.cell}>
                {Number(row[cellMap]).toLocaleString()}
            </TableCell>
            case "actionDate" : return <TableCell className={classes.cell}>
                {new Date(row[cellMap]).toLocaleDateString()}
            </TableCell>
            case "revenueType" : 
                if(row.paymentList){
                    const {paymentList} = row;
                    let purpose = [];
                    if(Array.isArray(paymentList)){
                        paymentList.map(item=>{
                            const revenueValue = hirSettingActions.getSettingValue(settings, "revenue", item.revenueType);
                            if(revenueValue) purpose.push(revenueValue);
                        })
                    }
                    return <TableCell className={classes.cell}>
                        {purpose.join(", ").length > 25 ?  String(purpose.join(", ")).substr(0, 25) + "..." : purpose.join(", ")}
                    </TableCell>
                }else{
                    let revenueName = row[cellMap];
                    if(settings){
                        const revenueTypes = settings.find(item=>item.name === "revenue");
                        if(revenueTypes){
                            const revenue = revenueTypes.values.find(item=>item.name === row[cellMap]);
                            revenueName = revenue && revenue.value;
                        }
                    }
                    return <TableCell className={classes.cell}>
                        {revenueName}
                    </TableCell>
                }
            case "_id" : return <TableCell className={classes.cell}>
                {String(row[cellMap]).substr(0, 6)}...
            </TableCell> 
            default : return <TableCell className={classes.cell}>
                {row[cellMap]}
            </TableCell>
        }
    }
    editPaymentDialog = paymentData => e => {
        e.stopPropagation();
        this.setState({newPayDialog : true, editMode : true, paymentData})
    }
    editPayment(data, context){
        const {paymentData} = this.state;
        const paymentId = paymentData._id;
        const {dispatch, patientId, patient, updateUser} = this.props;
        data = {...paymentData, ...data, amount : parseInt(data.amount)};
        delete data._id;
        hirPatientActions.updatePayment(patientId, paymentId, data, (done, result) => {
            context && context.setState({loading : false});
            updateUser && updateUser({updateHeader : false})
            if(done) {
                let lastName, firstName;
                if(patient && patient.myProfile){
                    const {myProfile} = patient;
                    lastName = myProfile.lastName;
                    firstName = myProfile.firstName;
                }
                this.setState({
                    newPayDialog : false, 
                    editMode : false, 
                    payment : { ...result, name : lastName && lastName + ", "+firstName},  
                    printDialog : true,
                    paymentData
                });                
            }
        })(dispatch);
    }
    openNewMenu(e){
        const anchorEl = e.target;
        this.setState(state=>({anchorEl : state.anchorEl ? null : anchorEl}))
    }
    render() {
        const {
            classes, patient, patientId, [hirPatientStrings.patientPayments] : patientPayments} = this.props;
        const { newPayDialog,editMode, payment, printDialog, paymentData, anchorEl, multiple} = this.state;
        let payments;
        if(patientPayments){
            payments = patientPayments[patientId];
        }
        return (
            <div className={classes.root}>
                <MyTable
                    classes={{root : classes.table, tableWrapper : classes.tableWrapper}}
                    elevation={0}
                    title="Payments"
                    header={["ID", "Purpose", "Amount", "Date", "Method", "Group", "Action"]}
                    dataMap={["_id", "revenueType", "amount","actionDate", "accountAction", "groupId", "action"]}
                    data={payments || []}
                    CellMap={this.cellMapFormat.bind(this)}
                    rowAction={payment=>()=>this.setState({payment, printDialog : true})}
                    />
                    <Fab 
                        onClick={this.openNewMenu.bind(this)}
                        className={classes.fab} size="small">
                        <Add className={classes.icon}/>
                    </Fab>
                    <Menu anchorEl={anchorEl}
                        open={Boolean(anchorEl)}
                        onClose={()=>this.setState({anchorEl : null, multiple : false})}>
                            <MenuItem onClick={()=>this.setState({newPayDialog : true, anchorEl : null})}>
                                Single Payment
                            </MenuItem>
                            <MenuItem onClick={()=>this.setState({newPayDialog : true, multiple : true, achorEl : null})}>
                                Multiple Payment
                            </MenuItem>
                        </Menu>
                <MyDialog 
                    open={newPayDialog}
                    close={()=>this.setState({newPayDialog :false, editMode : false, multiple : false, paymentData : null})}>
                        {multiple ? 
                            <HIRMultiplePayment
                                patient={patient}
                                postPayment={this.postPayment.bind(this)}/>
                            :
                            <HIRNewPayment
                                patient={patient}
                                postPayment={this.postPayment.bind(this)}
                                editMode={editMode}
                                editPayment={editMode ? this.editPayment.bind(this) : null}
                                paymentData={paymentData}
                            />
                        }
                    </MyDialog>
                <MyDialog 
                    classes={{
                        dialogPaper : classes.dialogPaper
                    }}
                    open={printDialog}
                    close={()=>this.setState({printDialog :false})}>
                        {multiple ? 
                            <HIRReceiptMultiple
                                payment={payment}/> :
                            <HIRReceipt
                                payment={payment}/>}
                    </MyDialog>
            </div>
        );
    }
}


_HIRPayments.propTypes = {
    classes : PropTypes.object.isRequired,
    patient : PropTypes.object,
    patientId : PropTypes.number,
    updateUser : PropTypes.func,
};
const mapStateToProps = ({hirPatientReducer, hirSettingReducer, hirUtilReducer}) => ({
    [hirPatientStrings.patientPayments] : hirPatientReducer[hirPatientStrings.patientPayments],
    [hirSettingStrings.settings] : hirSettingReducer[hirSettingStrings.settings],
    [hirUtilStrings.myProfile] : hirUtilReducer[hirUtilStrings.myProfile],
})


export const HIRPayments = connect(mapStateToProps)(withStyles(style)(_HIRPayments));
export {HIRPayments as default}