import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, MyDialog } from '../../utils';
import { history } from '../../../../helpers';
import { hirRouteNames } from '../../routeNames';
import { HIRGeneralInfo } from './HIRGeneralInfo';
import { Grid } from '@material-ui/core';
import { HIRPayments } from './HIRPayments';
import HIRAppointments from './HIRAppointments/HIRAppointments';
import { hirUtil } from '../../utils';
import { HIRNewPatient } from '../HIRNewPatient';
import { hirPatientActions } from '../actions';
import { hirPatientStrings } from '../config';
import { HIRPatientStatistics } from './HIRPatientStatistics';
import HIRPatientCreditDebit from './HIRPatientCreditDebit/HIRPatientCreditDebit';
import HIRPatientDeposit from './HIRPatientDeposit/HIRPatientDeposit';
import { HIRPatientDebtSettlement } from './HIRPatientDebtSettlement';
import { hirAccountActions } from '../../HIRAccounts';
import { HIRPatientViewClinics } from './HIRPatientViewClinics';
import HIRPatientDeletePaymentHx from './HIRPatientDeletePaymentHx/HIRPatientDeletePaymentHx';


const style = theme => ({
    root: {
    },
    components : {
        padding : 10,
        borderRadius : 20,
        backgroundColor : hirUtil.getTheme().background,
        minHeight : 100,
        position : "relative",
    },
    fab : {
        position : "absolute",
        right : 10,
        bottom : 10,
        backgroundColor : hirUtil.getTheme().primary1,
        color : hirUtil.getTheme().background,
        "&:hover" : {
            backgroundColor : hirUtil.getTheme().primaryDark,
        }
    },
    icon : {
        color : hirUtil.getTheme().background,
    }
})
class _HIRPatientView extends Component {
    constructor(props) {
        super(props);
        this.state={
            profileEditDialog : false
        }
        const {dispatch} = props;
        this.patientId = parseInt(props.match.params.id);
        //TODO
        //refactor so that state will contain data and from varaible
        this.state.patient = this.patient = this.props.location.state;
        if(this.patient){
            this.createHeader(this.patient, hirRouteNames.patients, dispatch);
            this.fromRoute = hirRouteNames.patients;
        }else this.fromRoute = hirRouteNames.appointments;
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : hirRouteNames.dashboard},
            {name : "Patients", path : hirRouteNames.patients},
            {name : "View", path : hirRouteNames.patientView}
        ])(dispatch);
        
    }
    createHeader(patient, routeName, dispatch){
        const {lastName, firstName} = patient.myProfile;
        let headerOptions = {
            [headerStrings.backButtonAction] : ()=>{}, // ()=>history.replace(routeName)
        }
        if(lastName){
            headerOptions[headerStrings.headerTitle] = lastName + " " + firstName + 
                "  [" + String(patient._id).padStart(6, "0") + "]"
        }
        headerActions(headerOptions)(dispatch);
    }
    componentDidMount() {
        this.getThisPatient();
    }
    getThisPatient(option={}){
        const {updateHeader = true} = option;
        const {dispatch} = this.props;
        hirPatientActions.getAPatient(this.patientId, (done, result)=>{
            if(done){
                this.setState({patient : result});
                this.patient = result;
                updateHeader && this.createHeader(this.patient, this.fromRoute, dispatch);
            }
        })(dispatch);
    }
    editRecord(data, context){
        const {dispatch} = this.props;
        
        hirPatientActions.editRecord(this.patient._id, data, (done)=>{
            const {patient} = this.state;
            context.setState({loading : false});
            if(done){
                this.setState({
                    profileEditDialog : false,
                    patient : {
                        ...patient,
                        myProfile : {
                            ...patient.myProfile,
                            ...data
                        }
                    }
                });
                this.patient.myProfile = {...this.patient.myProfile, ...data};
                const {lastName, firstName} = data;
                headerActions({
                    [headerStrings.headerTitle] : lastName + " " + firstName + 
                    "  [" + String(this.patient._id).padStart(6, "0") + "]"
                })(dispatch);
            }
        })(dispatch);
    }
    getLastNextAppointment(appointments){
        let appointInfo = {next : null, last : null};
        if(appointments && appointments[0]){
            appointInfo.next = appointments[0];
            if(appointments[0].visit){
                appointInfo.last = appointments[0]
            }else{
                for (let i = 0; i < appointments.length; i++) {
                    const appoint = appointments[i];
                    if(appoint.visit){
                        appointInfo.last = appoint;
                        break;
                    }
                }
            }
        }
        return appointInfo;
    }
    refundCredit(data){
        const {dispatch} = this.props;
        hirAccountActions.refundCredit(data, done => {
            done && this.getThisPatient()
        })(dispatch);
    }
    render() {
        const {classes, [hirPatientStrings.patientAppointments] : patientAppointments} = this.props;
        const {
            profileEditDialog, patient,            
        } = this.state;
        return (
            <div className={classes.root}>
                <Grid container spacing={2}>
                    <Grid item xs={12} sm={12} md={12} lg={12} xl={12}>
                        <HIRGeneralInfo classes={{
                            root : classes.components,
                            fab : classes.fab,
                            icon : classes.icon,
                        }}
                        patientInfo={patient}
                        lastNextAppointment={this.getLastNextAppointment(patientAppointments && patientAppointments[this.patientId])}
                        fabOnClick={()=>this.setState({profileEditDialog : true})}/>
                    </Grid>
                    <Grid item xs={12} sm={12} md={12} lg={12} xl={12}>
                        <HIRPatientCreditDebit
                            patient={patient}
                            refund={this.refundCredit.bind(this)}
                        />
                    </Grid>
                    <Grid item xs={12} sm={12} md={12} lg={12} xl={12}>
                        <HIRPatientViewClinics
                            patient={patient}
                            updatePatient={this.getThisPatient.bind(this)}
                        />
                    </Grid>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <HIRPatientDeposit
                            patientId={this.patientId}
                            classes={{
                                root : classes.components,
                                fab : classes.fab,
                                icon : classes.icon,
                            }}
                            updatePatient={this.getThisPatient.bind(this)}
                        />
                    </Grid>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <HIRPayments classes={{
                            root : classes.components,
                            fab : classes.fab,
                            icon : classes.icon,
                        }}
                            patient={patient}
                            patientId={this.patientId}
                            updateUser={this.getThisPatient.bind(this)}
                            />
                    </Grid>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        {hirUtil.isAdmin() && <HIRPatientDeletePaymentHx
                            patientId={this.patientId}
                            updatePatient={this.getThisPatient.bind(this)}
                        />}
                        <div style={{marginTop : 20}}>
                            <HIRPatientDebtSettlement
                                patientId={this.patientId}
                                classes={{
                                    root : classes.components,
                                    fab : classes.fab,
                                    icon : classes.icon,
                                }}
                            />
                        </div>
                    </Grid>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <HIRAppointments classes={{
                                root : classes.components,
                                fab : classes.fab,
                                icon : classes.icon,
                            }}
                            patient={patient}
                            patientId={this.patientId}/>
                    </Grid>
                </Grid>
                <MyDialog 
                    open={profileEditDialog}
                    close={()=>this.setState({profileEditDialog : false})}>
                        <HIRNewPatient
                            data={patient ? patient.myProfile : {}}
                            edit
                            editRecord={this.editRecord.bind(this)}
                        />
                </MyDialog>
                <HIRPatientStatistics
                    patientId={this.patientId}
                    familyId={this.patient && this.patient.familyId}/>
            </div>
        );
    }
}


_HIRPatientView.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({hirPatientReducer}) => ({
    [hirPatientStrings.patientAppointments] : hirPatientReducer[hirPatientStrings.patientAppointments],
})


export const HIRPatientView = connect(mapStateToProps)(withStyles(style)(_HIRPatientView));
export {HIRPatientView as default}